fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let mut count = 0;
    for i in 0..m {
        for j in 0..n {
            if grid[i][j] > 0 {
                let mut queue = vec![(i, j)];
                let mut sum = 0;
                while let Some((x, y)) = queue.pop() {
                    sum += grid[x][y];
                    grid[x][y] = 0;
                    for (dx, dy) in [(0, 1), (1, 0), (0, -1), (-1, 0)] {
                        let nx = x as i32 + dx;
                        let ny = y as i32 + dy;
                        if nx >= 0 && ny >= 0 && nx < m as i32 && ny < n as i32 {
                            let nx_us = nx as usize;
                            let ny_us = ny as usize;
                            if grid[nx_us][ny_us] > 0 {
                                grid[nx_us][ny_us] = 0;
                                queue.push((nx_us, ny_us));
                            }
                        }
                    }
                }
                if sum % k == 0 {
                    count += 1;
                }
            }
        }
    }
    count as i64
}
